class Solution:
    def canConstruct(self, s: str, k: int) -> bool:
        char_count = {}
        for char in s:
            char_count[char] = char_count.get(char, 0) + 1
        odd_counts = sum(count % 2 for count in char_count.values())
        return odd_counts <= k and k <= len(s)
